def snake_to_camel(s):
    words = re.findall(r'[a-zA-Z]+', s)
    if not words:
        return ''
    return words[0].lower() + ''.join(word.capitalize() for word in words[1:])

assert snake_to_camel('android_tv') == 'AndroidTv'
